INSERT INTO public.first_scenes (
    portrait_id, build_type, narration, visual_scene,
    image_url, audio_url, choices, is_successful, retry_count
) VALUES (
    'f1',
    'mage',
    'A searing pain pulsed behind her eyes as she lay amongst splintered wood and overturned barrels, a dark pool of dry blood beneath her. (My head... it throbs. Everything''s blurry. Where am I? What happened?)',
    'A forest clearing, bathed in soft morning light. Shattered wooden barrels and scattered debris lie on the weathered ground, with a distinct, dark stain of dried blood.',
    'http://127.0.0.1:54331/storage/v1/object/public/character-images/first_scenes/scene_f1_mage.png',
    'http://127.0.0.1:54331/storage/v1/object/public/character-images/first_scenes/narration_f1_mage.mp3',
    '[{"id": "choice_1", "text": "Try to push herself up slowly and carefully survey the immediate surroundings."}, {"id": "choice_2", "text": "Fumble weakly for any items left on her person or nearby."}, {"id": "choice_3", "text": "Close her eyes and listen intently for any sounds or movement in the forest."}, {"id": "choice_4", "text": "Lie still for a moment, trying to force a single memory to surface."}]'::jsonb,
    TRUE,
    0
) ON CONFLICT (portrait_id, build_type) DO UPDATE SET
    narration = EXCLUDED.narration,
    visual_scene = EXCLUDED.visual_scene,
    image_url = EXCLUDED.image_url,
    audio_url = EXCLUDED.audio_url,
    choices = EXCLUDED.choices,
    is_successful = TRUE,
    retry_count = 0,
    last_error = NULL,
    generated_at = NOW();

