    '[{"id": "choice_1", "text": "Try to push myself up slowly, just to see if I can move."}, {"id": "choice_2", "text": "Pat down my clothes, checking if anything, anything at all, remains."}, {"id": "choice_3", "text": "Strain to listen beyond the ringing in my ears, for any nearby sounds."}, {"id": "choice_4", "text": "Close my eyes for a moment, wishing for a memory, any memory, to surface."}]'::jsonb,
    TRUE,
    0
) ON CONFLICT (portrait_id, build_type) DO UPDATE SET
    narration = EXCLUDED.narration,
    visual_scene = EXCLUDED.visual_scene,
    image_url = EXCLUDED.image_url,
    audio_url = EXCLUDED.audio_url,
    choices = EXCLUDED.choices,
    is_successful = TRUE,
    retry_count = 0,
    last_error = NULL,
    generated_at = NOW();

DO $$
DECLARE
    scene_count INTEGER;
BEGIN
    SELECT COUNT(*) INTO scene_count FROM public.first_scenes WHERE is_successful = TRUE;
    RAISE NOTICE 'Total successful first scenes: %', scene_count;
    IF scene_count < 32 THEN
        RAISE WARNING 'Expected 32 first scenes but found %', scene_count;
    END IF;
END $$;
